#!/usr/bin/env python3
from plugins.common.plugin_entry import nv_enrich_plugin

@nv_enrich_plugin("shape_aspect", result_scope="detection")
def process_job(job: dict) -> dict:
    """
    Calcula la relación de aspecto (alto/ancho) de una detección.
    """
    detection = job.get("detection")
    if not detection:
        return {"aspect_ratio": None}

    w = detection["x1n"] - detection["x0n"]
    h = detection["y1n"] - detection["y0n"]
    if w <= 0 or h <= 0:
        return {"aspect_ratio": None}

    return {
        "descriptors": {
            "aspect_ratio": round(h / w, 3)
        }
    }
